    questions: [ {q:"War Gregor MacGregor ein schottischer Soldat?", a_de:"Ja", a_tr:"Evet"}, {q:"Hieß das neue Land Poyais?", a_de:"Ja", a_tr:"Evet"}, {q:"Gab es in Poyais wirklich Städte und Gold?", a_de:"Nein", a_tr:"Hayır"}, {q:"Segelten die Menschen über den Ozean nach Poyais?", a_de:"Ja", a_tr:"Evet"}, {q:"Fanden sie ein tolles Paradies?", a_de:"Nein", a_tr:"Hayır"}, {q:"Sind viele Menschen im Dschungel gestorben?", a_de:"Ja", a_tr:"Evet"}, {q:"Wurde MacGregor von der Polizei bestraft?", a_de:"Nein", a_tr:"Hayır"} ]
