    questions: [ {q:"Lebte Jeanne in Frankreich?", a_de:"Ja", a_tr:"Evet"}, {q:"Wollte Marie Antoinette die Kette wirklich kaufen?", a_de:"Nein", a_tr:"Hayır"}, {q:"Täuschte Jeanne einen reichen Kardinal?", a_de:"Ja", a_tr:"Evet"}, {q:"Heuerte Jeanne eine Frau an, die wie die Königin aussah?", a_de:"Ja", a_tr:"Evet"}, {q:"Verkaufte Jeannes Ehemann die Diamanten in Paris?", a_de:"Nein", a_tr:"Hayır"}, {q:"Kam das Geheimnis am Ende ans Licht?", a_de:"Ja", a_tr:"Evet"}, {q:"Half der Skandal, die Revolution auszulösen?", a_de:"Ja", a_tr:"Evet"} ]
