lessonData["16_Pearlman.mp3"] = [{
    text: "16. Lou Pearlman. Lou Pearlman war in den 1990er Jahren sehr berühmt dafür, große Pop-Gruppen wie die Backstreet Boys und NSYNC zu gründen. Er wirkte wie ein sehr erfolgreicher, glücklicher und reicher Musikmanager. Er kaufte riesige Häuser, teure Autos und flog in Privatjets um die Welt. Aber er hatte ein sehr dunkles und gieriges Geheimnis. Zuerst stahl er fast das gesamte Geld seiner jungen Musikstars. Er ließ sie als Teenager sehr schlechte und ungerechte Verträge unterschreiben. Zweitens betrieb er im Hintergrund ein massives Ponzi-Schema. Er erfand komplett gefälschte Firmen und Banken. Er bat normale Leute, in seine Geschäfte zu investieren, und versprach schnelles viel Geld. Er stahl etwa 300 Millionen Dollar von Freunden, Familie und normalen Menschen. Als die Polizei seine gefälschten Firmen untersuchte, floh er nach Indonesien. Das FBI erwischte ihn, und ein Richter gab ihm 25 Jahre Haft. Er starb allein im Gefängnis, weit weg vom Rampenlicht und der lauten Musik seiner berühmten Vergangenheit.",
    dict: { "gründen":"kurmak", "wirkte":"görünüyordu", "erfolgreicher":"başarılı", "glücklicher":"mutlu", "musikmanager":"müzik menajeri", "riesige":"devasa", "häuser":"evler", "autos":"arabalar", "flog":"uçtu", "privatjets":"özel jetler", "gieriges":"açgözlü", "geheimnis":"sır", "zuerst":"ilk olarak", "stahl":"çaldı", "gesamte":"tüm", "musikstars":"müzik yıldızları", "schlechte":"kötü", "ungerechte":"adaletsiz", "verträge":"sözleşmeler", "unterschreiben":"imzalamak", "hintergrund":"arka plan", "erfand":"icat etti", "gefälschte":"sahte", "firmen":"şirketler", "geschäfte":"işler", "investieren":"yatırım yapmak", "versprach":"söz verdi", "familie":"aile", "untersuchte":"inceledi", "floh":"kaçı", "erwischte":"yakaladı", "haft":"hapis", "allein":"yalnız", "rampenlicht":"spot ışığı", "vergangenheit":"geçmiş" },
    questions: [ {q:"Gründete Lou Pearlman die Backstreet Boys?", a_de:"Ja", a_tr:"Evet"}, {q:"War er ein ehrlicher Musikmanager?", a_de:"Nein", a_tr:"Hayır"}, {q:"Unterschrieben die Musikstars sehr gute Verträge?", a_de:"Nein", a_tr:"Hayır"}, {q:"Betrieb er ein massives Ponzi-Schema?", a_de:"Ja", a_tr:"Evet"}, {q:"Stahl er etwa 300 Millionen Dollar?", a_de:"Ja", a_tr:"Evet"}, {q:"Floh er nach Indonesien?", a_de:"Ja", a_tr:"Evet"}, {q:"Starb er als reicher Mann in Freiheit?", a_de:"Nein", a_tr:"Hayır"} ]
}];

lessonData["17_Valfierno.mp3"] = [{
    text: "17. Eduardo de Valfierno. Eduardo de Valfierno ist berühmt für ein Verbrechen, das vielleicht ein Mythos ist, aber eine geniale und clevere Geschichte. Er nannte sich selbst einen wohlhabenden Marquis. Im Jahr 1911 wurde das berühmte Gemälde Mona Lisa aus dem Louvre in Paris gestohlen. Ein stiller Mann namens Vincenzo Peruggia stahl es tatsächlich. Aber Jahre später erzählte Valfierno einem Reporter, er sei der wahre Drahtzieher gewesen. Valfierno sagte, er habe nie vorgehabt, das echte Gemälde zu verkaufen. Vor dem großen Diebstahl bezahlte er einen exzellenten Künstler, sechs perfekte Kopien der Mona Lisa zu malen. Als das echte Bild gestohlen war, stand es in allen Zeitungen der Welt. Valfierno traf sich dann heimlich mit sechs verschiedenen reichen Käufern. Er verkaufte ihnen seine sechs Fälschungen für riesige Summen. Er sagte jedem Käufer, er bekomme das echte gestohlene Bild! Er machte Millionen und ließ den echten Dieb die ganze Schuld und das Gefängnis tragen. Es war ein perfektes Verbrechen, weil die reichen Käufer nie der Polizei sagen konnten, sie hätten gestohlene Kunst gekauft.",
    dict: { "vielleicht":"belki", "mythos":"mit/efsane", "geniale":"dahice", "selbst":"kendini", "wohlhabenden":"varlıklı", "marquis":"marki", "gemälde":"tablo", "gestohlen":"çalınmış", "stiller":"sessiz", "namens":"adında", "tatsächlich":"aslında", "später":"sonra", "erzählte":"anlattı", "wahre":"gerçek", "drahtzieher":"elebaşı", "vorgehabt":"niyetlenmiş", "echte":"gerçek", "verkaufen":"satmak", "diebstahl":"hırsızlık", "bezahlte":"ödedi", "exzellenten":"mükemmel", "künstler":"sanatçı", "perfekte":"kusursuz", "kopien":"kopyalar", "malen":"boyamak", "zeitungen":"gazeteler", "heimlich":"gizlice", "verschiedenen":"farklı", "käufern":"alıcılar", "fälschungen":"sahteler", "summen":"meblağlar", "bekomme":"aldığını", "dieb":"hırsız", "schuld":"suç/borç", "tragen":"taşımak", "kunst":"sanat" },
    questions: [ {q:"Wurde die Mona Lisa im Jahr 1911 aus dem Louvre gestohlen?", a_de:"Ja", a_tr:"Evet"}, {q:"Stahl Valfierno das Bild mit seinen eigenen Händen?", a_de:"Nein", a_tr:"Hayır"}, {q:"Ließ er sechs Kopien der Mona Lisa malen?", a_de:"Ja", a_tr:"Evet"}, {q:"Verkaufte er das echte Bild an sechs verschiedene Käufer?", a_de:"Nein", a_tr:"Hayır"}, {q:"Verkaufte er die sechs Kopien als das echte Bild?", a_de:"Ja", a_tr:"Evet"}, {q:"Machte er damit Millionen Dollar?", a_de:"Ja", a_tr:"Evet"}, {q:"Gingen die reichen Käufer am Ende zur Polizei?", a_de:"Nein", a_tr:"Hayır"} ]
}];

lessonData["18_Marco.mp3"] = [{
    text: "18. Enric Marco. Enric Marco war ein Mann aus Spanien, der eine schreckliche und traurige Lüge erzählte, nur um Aufmerksamkeit und Respekt zu bekommen. Viele Jahre lang war er Präsident einer großen Gruppe für Holocaust-Überlebende in Spanien. Er hielt hunderte emotionale Reden vor Schulen, Lehrern und Politikern. Er weinte echte Tränen, während er traurige Geschichten von seiner schweren Zeit im Nazi-KZ Flossenbürg im Zweiten Weltkrieg erzählte. Die Leute hielten ihn für einen großen und mutigen Helden. Er bekam sogar eine besondere Goldmedaille von der spanischen Regierung. Aber 2005 schaute ein kluger Historiker in die echten Kriegsdokumente. Der Historiker entdeckte eine schockierende Wahrheit. Marco war nie in einem Konzentrationslager! Er war tatsächlich als normaler Freiwilliger nach Deutschland gegangen, nicht als Gefangener. Er erfand die ganze traurige Geschichte nur, weil er bewundert werden und gehört werden wollte. Er musste seine besondere Medaille zurückgeben und lebte den Rest seines Lebens in großer Schande wegen seiner schrecklichen Lügen.",
    dict: { "spanien":"ispanya", "schreckliche":"korkunç", "traurige":"üzücü", "lüge":"yalan", "aufmerksamkeit":"ilgi", "respekt":"saygı", "präsident":"başkan", "gruppe":"grup", "holocaust-überlebende":"holokost kurtulanları", "hielt":"yaptı/tuttu (Reden halten: konuşma yapmak)", "emotionale":"duygusal", "reden":"konuşmalar", "schulen":"okullar", "lehrern":"öğretmenler", "politikern":"politikacılar", "weinte":"ağladı", "tränen":"gözyaşları", "helden":"kahraman", "goldmedaille":"altın madalya", "schaute":"baktı", "historiker":"tarihçi", "entdeckte":"keşfetti", "schockierende":"şok edici", "wahrheit":"gerçek", "konzentrationslager":"toplama kampı", "freiwilliger":"gönüllü", "gefangener":"esir", "bewundert":"hayran olunan", "gehört":"duyulmuş", "zurückgeben":"geri vermek", "schande":"utanç" },
    questions: [ {q:"War Enric Marco ein Präsident für Holocaust-Überlebende?", a_de:"Ja", a_tr:"Evet"}, {q:"Hielt er emotionale Reden vor Schulen?", a_de:"Ja", a_tr:"Evet"}, {q:"War er wirklich im Nazi-KZ Flossenbürg?", a_de:"Nein", a_tr:"Hayır"}, {q:"Bekam er eine Goldmedaille von der Regierung?", a_de:"Ja", a_tr:"Evet"}, {q:"Entdeckte ein Historiker die Wahrheit?", a_de:"Ja", a_tr:"Evet"}, {q:"War er ein Gefangener im Zweiten Weltkrieg?", a_de:"Nein", a_tr:"Hayır"}, {q:"Lebte er am Ende in Schande?", a_de:"Ja", a_tr:"Evet"} ]
}];

lessonData["19_Rocancourt.mp3"] = [{
    text: "19. Christophe Rocancourt. Christophe Rocancourt war ein armer Junge aus einer kleinen Stadt in Frankreich, wurde aber ein Meister der falschen Identitäten. In den 1990er Jahren zog er nach Los Angeles in Amerika. Er wollte Teil des reichen und berühmten Hollywood-Lebens werden. Also erzählte er den Leuten, er sei ein junger Mitglied der berühmten und reichen Rockefeller-Familie. Er trug sehr teure Anzüge, trank den besten Wein und fuhr unglaublich schnelle Autos. Er war sehr charmant und wurde schnell Freund von berühmten Filmschauspielern und reichen Geschäftsleuten. Er sagte seinen neuen reichen Freunden, er könne ihr Geld verdoppeln, wenn sie in seine geheimen Geschäfte investierten. Natürlich gab es gar keine echten Geschäfte. Er nahm ihr Geld nur, um sein eigenes Luxusleben zu finanzieren. Er stahl Millionen von Leuten, die ihn für ein Genie hielten. Die Polizei erwischte ihn schließlich in Kanada, wo er sich versteckte. Er kam ins Gefängnis, schrieb aber später ein populäres Buch über seine tollen Verbrechen. In Frankreich wurde er sogar ziemlich berühmt dafür, so ein cleverer Dieb zu sein.",
    dict: { "junge":"çocuk/genç", "kleinen":"küçük", "stadt":"şehir", "meister":"usta", "identitäten":"kimlikler", "zog":"taşındı", "reich":"zengin", "berühmt":"ünlü", "mitglied":"üye", "anzüge":"takım elbiseler", "trank":"içti", "wein":"şarap", "schnelle":"hızlı", "autos":"arabalar", "freund":"arkadaş", "verdoppeln":"ikiye katlamak", "natürlich":"tabii ki", "luxusleben":"lüks yaşam", "finanzieren":"finanse etmek", "kanada":"kanada", "versteckte":"gizlendi", "populäres":"popüler", "buch":"kitap", "cleverer":"zeki", "dieb":"hırsız" },
    questions: [ {q:"Ist Christophe Rocancourt in Amerika geboren?", a_de:"Nein", a_tr:"Hayır"}, {q:"Sagte er, er sei ein Mitglied der Rockefeller-Familie?", a_de:"Ja", a_tr:"Evet"}, {q:"Trug er teure Anzüge ve trank guten Wein?", a_de:"Ja", a_tr:"Evet"}, {q:"Hatte er echte Geschäfte, um Geld zu verdoppeln?", a_de:"Nein", a_tr:"Hayır"}, {q:"Stahl er Millionen von reichen Leuten?", a_de:"Ja", a_tr:"Evet"}, {q:"Erwischte die Polizei ihn in Kanada?", a_de:"Ja", a_tr:"Evet"}, {q:"Schrieb er ein Buch über seine Verbrechen?", a_de:"Ja", a_tr:"Evet"} ]
}];

lessonData["20_Soapy.mp3"] = [{
    text: "20. Soapy Smith. Soapy Smith war ein berühmter und sehr cleverer Betrüger im amerikanischen „Wilden Westen“ der 1800er Jahre. Sein richtiger Name war Jefferson Randolph Smith. Er bekam seinen lustigen Spitznamen „Soapy“ wegen seines Lieblingstricks auf der Straße. Er stand auf der schmutzigen Straße mit einer großen Menge Zuschauern. Er wickelte normale, billige Seifenstücke in Papier. Aber er ließ die Menge klar sehen, wie er ein paar Stücke mit 100-Dollar-Scheinen einwickelte. Er mischte alle Seifen in einer Tasche und verkaufte sie für je einen Dollar. Arme Leute kauften die Seife in der Hoffnung auf das große Geld. Aber Smith nutzte sehr schnelle Zaubertricks. Er nahm heimlich das Geld heraus oder ließ seine geheimen Freunde in der Menge die Gewinner-Seife kaufen. Die normalen Leute bekamen nur normale Seife. Später in seinem Leben zog er während des berühmten Goldrausches nach Alaska. Er kontrollierte eine ganze Stadt mit seiner großen kriminellen Bande. Er betrieb gefälschte Telegrafenbüros und manipulierte Kartenspiele, bis er schließlich in einem berühmten Schusswechsel auf den Docks getötet wurde.",
    dict: { "wilden":"vahşi", "westen":"batı", "richtiger":"gerçek", "lustigen":"komik", "spitznamen":"takma ad", "seifenstücke":"sabun kalıpları", "papier":"kağıt", "menge":"kalabalık/miktar", "zuschauern":"izleyiciler", "wickelte":"sardı", "scheinen":"banknotlar (100-Dollar-Scheinen)", "mischte":"karıştırdı", "tasche":"çanta", "hoffnung":"umut", "zaubertricks":"sihirbazlık numaraları", "heraus":"dışarı (herausnehmen: çıkarmak)", "gewinner-seife":"kazanan sabun", "goldrausches":"altına hücum", "alaska":"alaska", "kontrollierte":"kontrol etti", "kriminelle":"suçlu", "bande":"çete", "betrieb":"işletti", "telegrafenbüros":"telgraf ofisleri", "manipulierte":"manipüle etti", "kartenspiele":"kart oyunları", "schusswechsel":"çatışma", "docks":"rıhtımlar", "getötet":"öldürüldü" },
    questions: [ {q:"War Jefferson Randolph Smith sein richtiger Name?", a_de:"Ja", a_tr:"Evet"}, {q:"Wickelte er Geld in Seifenstücke ein?", a_de:"Ja", a_tr:"Evet"}, {q:"Gewannen die armen Leute oft das große Geld?", a_de:"Nein", a_tr:"Hayır"}, {q:"Nutzte Smith Zaubertricks für seinen Betrug?", a_de:"Ja", a_tr:"Evet"}, {q:"Zog er später nach Alaska?", a_de:"Ja", a_tr:"Evet"}, {q:"Kontrollierte er eine Stadt mit einer Čete?", a_de:"Ja", a_tr:"Evet"}, {q:"Starb er friedlich im Alter?", a_de:"Nein", a_tr:"Hayır"} ]
}];

lessonData["21_Natwarlal.mp3"] = [{
    text: "21. Natwarlal. Natwarlal war Indiens berühmtester und cleverster Betrüger. Ursprünglich war er ein kluger Anwalt, merkte aber, dass er sehr gut darin war, die Handschrift und Unterschriften anderer zu fälschen. Er nutzte diese besondere Fähigkeit, um viel Geld von großen Banken und reichen Firmen zu stehlen. Er war ein Meister der Verkleidung und wechselte oft Kleidung und Gesicht, um der Polizei zu entkommen. Aber seine berühmtesten und lustigsten Verbrechen waren, öffentliche Denkmäler an Ausländer zu verkaufen. Er tat so, als wäre er ein wichtiger Regierungsbeamter. Er fand reiche ausländische Touristen und „verkaufte“ ihnen den wunderschönen Taj Mahal! Er tat das tatsächlich dreimal. Er verkaufte auch erfolgreich das riesige Rote Fort und das sehr wichtige indische Parlamentsgebäude. Er wurde viele Male verhaftet, und Richter gaben ihm insgesamt 113 Jahre Gefängnis. Aber er war ein Experte im Ausbrechen aus dem Gefängnis. Er entkam neunmal. Beim letzten Mal war er 84 Jahre alt und saß im Rollstuhl! Niemand hat ihn je wieder gesehen.",
    dict: { "indien":"hindistan", "cleverster":"en zeki", "ursprünglich":"başlangıçta", "anwalt":"avukat", "handschrift":"el yazısı", "unterschriften":"imzalar", "fälschen":"taklit etmek", "fähigkeit":"yetenek", "firmen":"şirketler", "verkleidung":"kılık değiştirme", "gesicht":"yüz", "entkommen":"kaçmak", "verbrechen":"suçlar", "ausländer":"yabancılar", "taj-mahal":"tac mahal", "dreimal":"üç kez", "rote":"kırmızı", "fort":"kale", "parlamentsgebäude":"parlamento binası", "insgesamt":"toplamda", "ausbrechen":"kaçmak/firar etmek", "entkam":"kaçtı", "neunmal":"dokuz kez", "rollstuhl":"tekerlekli sandalye", "niemand":"hiç kimse" },
    questions: [ {q:"War Natwarlal ein berühmter Betrüger in Indien?", a_de:"Ja", a_tr:"Evet"}, {q:"Konnte er Unterschriften perfekt fälschen?", a_de:"Ja", a_tr:"Evet"}, {q:"Verkaufte er den Taj Mahal wirklich?", a_de:"Ja", a_tr:"Evet"}, {q:"Verkaufte er das Parlamentsgebäude nur einmal?", a_de:"Nein", a_tr:"Hayır"}, {q:"Wurde er zu 113 Jahren Gefängnis verurteilt?", a_de:"Ja", a_tr:"Evet"}, {q:"Entkam er neunmal aus dem Gefängnis?", a_de:"Ja", a_tr:"Evet"}, {q:"War er beim letzten Ausbruch 20 Jahre alt?", a_de:"Nein", a_tr:"Hayır"} ]
}];
